module verified_counter_4bit(
    input clk,
    input rst,
    input en,

    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin
        if (rst) 
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
endmodule
